import { useEffect, useState } from "react";

function App() {
  const [loading, setLoading] = useState(true);
  const [coins, setCoins] = useState([]);
  const [coinValue, setCoinValue] = useState(0);
  const [dollor, setDollor] = useState(0);
  useEffect(() => {
    fetch("https://api.coinpaprika.com/v1/tickers?limit=10")
      .then((response) => response.json())
      .then((json) => {
        setCoins(json);
        setLoading(false);
      });
  }, []);
  function onSelect(event) {
    setCoinValue(event.target.value);
  }
  function onChangeDollor(event) {
    setDollor(event.target.value);
  }

  return (
    <div>
      <h1>The Coins!{loading ? "" : `(${coins.length})`}</h1>
      {loading ? (
        <strong>Loading...</strong>
      ) : (
        <select onChange={onSelect}>
          <option>Select coin</option>
          {coins.map((coin) => (
            <option key={coin.id} value={coin.quotes.USD.price}>
              {coin.name}({coin.symbol}): ${coin.quotes.USD.price.toFixed(8)}{" "}
              USD
            </option>
          ))}
        </select>
      )}
      <div>
        <label htmlFor="dollor">IF you have $</label>
        <input
          value={dollor}
          id="dollor"
          onChange={onChangeDollor}
          type="number"
          placeholder="type"
        />
        <h3>You can buy {dollor/coinValue}</h3>
      </div>
    </div>
  );
}

export default App;
